      import org.ascn.utils.QueryUtils;
		  import org.ascn.webservices.GSuiteAPI;
		  
		  trace(logName,"Entering Step: "+wfcontext.getStep().getName());
		  addMessage(wfcontext, "Entering Step: "+wfcontext.getStep().getName());
		  
		  GSuiteAPI g = new GSuiteAPI();
		  try {
			  List requiredArgs = getRequiredVariables(workflow);
			  List validationMessages = validateArguments(workflow,requiredArgs);
			  for(String outMsg : validationMessages){
				if(outMsg.startsWith("ERROR")){
					addMessage(wfcontext, "ERROR In Step: "+wfcontext.getStep().getName()+" "+outMsg);
					errorMsg = errorMsg+"\n"+outMsg;
					throw new RuntimeException("ERROR Arguments can not be null: "+errorMsg); 
				}
			 }
			  
			  List targetList = new ArrayList();
			  targetList.add(workflow.get("requesterPrimaryEmail"));
			  targetList.add(workflow.get("groupPrimaryEmail"));
		  } catch(Exception e) {
		    errorMsg = "Exception encountered in: "+wfcontext.getStep().getName()+" "+e;
			error(logName, errorMsg,e);
			workflow.put("Message", errorMsg);
			handleWorkFlowException(wfcontext, e);
		  }
		  addMessage(wfcontext, "Exiting Step: "+wfcontext.getStep().getName());
          trace(logName,"Exiting Step: "+wfcontext.getStep().getName());
		  return errorMsg;

          import org.ascn.utils.QueryUtils;
		  import org.ascn.webservices.GSuiteAPI;
		  trace(logName,"Entering Step: "+wfcontext.getStep().getName());
		  addMessage(wfcontext, "Entering Step: "+wfcontext.getStep().getName());
		  
		  String parentGroup = workflow.get("groupPrimaryEmail");
		  String memberGroup = workflow.get("requesterPrimaryEmail");
		  
		  try{
			GSuiteAPI g = new GSuiteAPI();
			addGSuiteGroupMember(parentGroup,memberGroup);
			if (getResponseCode() != 200) {
				String outMsg = "RESPONSE: Add Group Member: "+getResponseMessage();
				addMessage(wfcontext, wfcontext.getStep().getName()+" "+outMsg);
				workflow.put("Message",outMsg);
			} else{
			    errorMsg = nu;
				errorMsg = "ERROR: Could not add Group Member: "+getResponseCode()+"\n"+getErrorMessage();
				addMessage(wfcontext, wfcontext.getStep().getName()+" "+errorMsg);
				workflow.put("Message",errorMsg);
			}
		  } catch(Exception e) {
		    errorMsg = null;
			errorMsg = "Exception encountered in: "+wfcontext.getStep().getName()+" "+e;
			error(logName, errorMsg,e);
			workflow.put("Message", errorMsg);
			handleWorkFlowException(wfcontext, e);
		  }
